#!/usr/bin/env bash
# shellcheck disable=SC2155,SC2034
# Generates a FIPS-specific MTA extension file that enables FIPS 140-3 mode
# for all autoscaler microservices. Apply this extension in addition to the
# base extension file generated by build-extension-file.sh.

set -euo pipefail

script_dir="$(cd -- "$(dirname -- "${BASH_SOURCE[0]}")" &> /dev/null && pwd)"
# shellcheck source=scripts/vars.source.sh
source "${script_dir}/vars.source.sh"
DEST="${DEST:-/tmp/build}"

echo "Building FIPS extension file for autoscaler deployment with version ${VERSION}"
fips_extension_file_path="${DEST}/extension-file-fips-${VERSION}.txt"
mkdir -p "${DEST}"

# Exit early if extension file already exists
if [ -f "${fips_extension_file_path}" ]; then
  echo "FIPS extension file already exists at: ${fips_extension_file_path}"
  echo "Skipping rebuild. Delete the file to regenerate it."
  exit 0
fi

cat <<EOF > "${fips_extension_file_path}"
ID: fips-mode
extends: development
version: 1.0.0
_schema-version: 3.3.0

modules:
  - name: apiserver
    properties:
      GOFIPS140: v1.0.0
      GODEBUG: "fips140=only,tlsmlkem=0"
  - name: eventgenerator
    properties:
      GOFIPS140: v1.0.0
      GODEBUG: "fips140=only,tlsmlkem=0"
  - name: metricsforwarder
    properties:
      GOFIPS140: v1.0.0
      GODEBUG: "fips140=only,tlsmlkem=0"
  - name: operator
    properties:
      GOFIPS140: v1.0.0
      GODEBUG: "fips140=only,tlsmlkem=0"
  - name: scalingengine
    properties:
      GOFIPS140: v1.0.0
      GODEBUG: "fips140=only,tlsmlkem=0"

resources:
  - name: apiserver-config
    parameters:
      config:
        apiserver-config:
          fips_mode: true
  - name: eventgenerator-config
    parameters:
      config:
        eventgenerator-config:
          fips_mode: true
  - name: scalingengine-config
    parameters:
      config:
        scalingengine-config:
          fips_mode: true
  - name: metricsforwarder-config
    parameters:
      config:
        metricsforwarder-config:
          fips_mode: true
  - name: operator-config
    parameters:
      config:
        operator-config:
          fips_mode: true
  - name: scheduler-config
    parameters:
      config:
        autoscaler:
          fips_mode: true
  - name: acceptance-tests-config
    parameters:
      config:
        acceptance-tests-config:
          fips_mode_expected: true
EOF

echo "FIPS MTA extension file created at: ${fips_extension_file_path}"
